+  // Deal to tableau (1 card to col 1, 2 to col 2, etc.)
+  let cardIndex = 0
+  for (let col = 0; col < 7; col++) {
+    for (let row = 0; row <= col; row++) {
+      const card = { ...deck[cardIndex], faceUp: row === col }
+      tableau[col].push(card)
